/**
 * github-commands.mjs
 *
 * Dispatcher used by cli.mjs when --backend=github. Routes the same command
 * verbs (atom, entity, moc, source, synthesis, query, log) to the
 * lib/molecular/github-backend.mjs Contents-API helpers.
 *
 * Tasks deliberately not implemented in github mode:
 *   - graph    : regenerated by /api/cron/rebuild-graph (Step 4)
 *   - reindex  : same — server-cron-only
 *   - lint     : same — runs against the live tree from cron
 *   - touch / supersede / migrate-decay : Step 4
 *
 * `--scope` flag must be present (JSON or shorthand). When omitted, the
 * dispatcher tries to infer scope.repo from `git remote get-url origin`.
 */
import { execSync } from 'node:child_process'
import { mkdir, writeFile, readFile, readdir, stat } from 'node:fs/promises'
import { existsSync } from 'node:fs'
import { dirname, join, relative, sep } from 'node:path'
import { homedir } from 'node:os'
import {
  getItem,
  putItem,
  listItems,
  appendLogEvent,
  scopeIdFor,
  pathFor,
  getFile,
  putFile,
  getTree,
} from '../../../lib/molecular/github-backend.mjs'

const KIND_FOR = {
  atom: 'atoms',
  entity: 'entities',
  moc: 'mocs',
  source: 'sources',
  synthesis: 'synthesis',
}

export async function dispatch(cmd, positional, flags) {
  // Repo-wide commands — no scope needed.
  if (cmd === 'framework-pull') return cmdFrameworkPull(flags)
  if (cmd === 'framework-push') return cmdFrameworkPush(flags)
  const scope = resolveScope(flags)
  switch (cmd) {
    case 'atom':      return cmdItem('atom', positional, flags, scope)
    case 'entity':    return cmdEntity(positional, flags, scope)
    case 'moc':       return cmdItem('moc', positional, flags, scope)
    case 'source':    return cmdItem('source', positional, flags, scope)
    case 'synthesis': return cmdItem('synthesis', positional, flags, scope)
    case 'log':       return cmdLog(positional, flags, scope)
    case 'query':     return cmdQuery(positional.join(' '), flags, scope)
    case 'init':      return ok({ note: 'init is a no-op for --backend=github (repo already exists or is bootstrapped via T2d)' })
    case 'graph':
    case 'reindex':
    case 'lint':
      return ok({ skipped: cmd, reason: 'github mode: this op is owned by /api/cron/rebuild-graph (Step 4)' })
    case 'touch':
    case 'supersede':
    case 'migrate-decay':
      return ok({ skipped: cmd, reason: 'github mode: decay ops are deferred to Step 4' })
    default:
      throw new Error(`unknown command for --backend=github: ${cmd}`)
  }
}

function resolveScope(flags) {
  const raw = flags.scope
  if (raw && typeof raw === 'string') {
    if (raw.startsWith('{')) return JSON.parse(raw)
    const out = {}
    for (const part of raw.split(',')) {
      const idx = part.indexOf(':')
      if (idx < 0) continue
      const k = part.slice(0, idx).trim()
      const v = part.slice(idx + 1).trim()
      if (k === 'repo') out.repo = v
      else if (k === 'business' || k === 'business_slug') out.business_slug = v
      else if (k === 'namespace' || k === 'ns') out.namespace = v
    }
    return out
  }
  // Infer from `git remote get-url origin` -> "owner/name"
  try {
    const url = execSync('git remote get-url origin', { encoding: 'utf8' }).trim()
    const m = url.match(/[:/]([^/]+\/[^/]+?)(\.git)?$/)
    if (m) return { repo: m[1] }
  } catch (_) {
    /* not a git repo or no origin */
  }
  throw new Error('--scope is required (or run inside a git repo with origin set). Example: --scope=repo:pinnacleadvisors/nexus')
}

async function cmdItem(verb, positional, flags, scope) {
  const kind = KIND_FOR[verb]
  const title = positional[0]
  if (!title) throw new Error(`usage: ${verb} <title> [--fact|--body|--description=...] [--scope=...]`)
  const slug = slugify(title)
  const fact = flags.fact || flags.body || flags.description || ''
  const author = process.env.MEMORY_AUTHOR || 'cli'
  const locators = parseLocators(flags.locator || flags.locators)
  const fm = {
    type: verb,
    title,
    slug,
    scope,
    author,
    importance: flags.importance || 'normal',
    kind: flags.kind || 'fact',
    locators,
    created: new Date().toISOString().slice(0, 10),
    sources: flags.source ? [flags.source] : [],
    links: splitList(flags.links),
  }
  const body = renderNote(fm, fact)
  const existing = await getItem(kind, scope, slug)
  const result = await putItem(kind, scope, slug, body, existing?.sha)
  await appendLogEvent(scope, `create-${verb}`, title, result.html_url)
  ok({ created: result.html_url, slug, scopeId: scopeIdFor(scope), action: result.action })
}

async function cmdEntity(positional, flags, scope) {
  const [type, name] = positional
  if (!type || !name) throw new Error('usage: entity <type> <name> [--description=...] [--scope=...]')
  return cmdItem('entity', [name], { ...flags, kind: type }, scope)
}

async function cmdLog(positional, flags, scope) {
  const op = positional[0]
  const title = positional.slice(1).join(' ') || op
  const ref = flags.ref || ''
  const r = await appendLogEvent(scope, op, title, ref)
  ok({ logged: r.html_url })
}

async function cmdQuery(text, flags, scope) {
  // Github mode query: list slugs in scope and grep titles. For full-text
  // search use the Supabase reader (Step 5). This is intentionally minimal.
  const kinds = ['atoms', 'entities', 'mocs', 'sources', 'synthesis']
  const hits = []
  const needle = text.toLowerCase()
  for (const kind of kinds) {
    const slugs = await listItems(kind, scope)
    for (const s of slugs) {
      if (s.toLowerCase().includes(needle)) {
        hits.push({ kind, slug: s, path: pathFor(kind, scope, s) })
      }
    }
  }
  ok({ query: text, scope, hits })
}

// ── small helpers (kept local; mirror cli.mjs) ──────────────────────────────

function slugify(s) {
  return String(s)
    .toLowerCase()
    .replace(/[^\w\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80)
}

function splitList(v) {
  if (!v || v === true) return []
  return String(v).split(',').map((s) => s.trim()).filter(Boolean)
}

function parseLocators(v) {
  if (!v || v === true) return []
  // Accept JSON array, or shorthand "kind:value;kind:value"
  if (typeof v === 'string' && v.trim().startsWith('[')) return JSON.parse(v)
  const out = []
  for (const item of String(v).split(';')) {
    const idx = item.indexOf(':')
    if (idx < 0) continue
    const kind = item.slice(0, idx).trim()
    const value = item.slice(idx + 1).trim()
    if (kind === 'url') out.push({ kind: 'url', href: value })
    else if (kind === 'youtube') out.push({ kind: 'youtube', video_id: value })
    else if (kind === 'github') {
      const [repo, path] = value.split('@')[0].split('#')[0].split('|')
      out.push({ kind: 'github', repo, path })
    }
    // For r2/s3/local etc., users should pass JSON via --locators=[...]
  }
  return out
}

function renderNote(fm, fact) {
  const yaml = ['---']
  for (const [k, v] of Object.entries(fm)) {
    if (v === undefined || v === null) continue
    if (Array.isArray(v) && v.length === 0) continue
    yaml.push(`${k}: ${typeof v === 'string' ? v : JSON.stringify(v)}`)
  }
  yaml.push('---', '')
  if (fact) yaml.push(fact, '')
  return yaml.join('\n')
}

function ok(obj) {
  console.log(JSON.stringify({ ok: true, ...obj }))
}

// ── framework-pull / framework-push ─────────────────────────────────────────
//
// The cross-model agent framework lives at framework/* in memory-hq.
// `framework-pull` downloads it onto the local device (defaults to
// ~/.claude/framework). `framework-push` uploads docs/framework/* from
// a nexus checkout. Both help any device stay in sync with the latest
// principles + per-model adapters without git-cloning memory-hq.

async function cmdFrameworkPull(flags) {
  const dest = expandHome(flags.to || join('~', '.claude', 'framework'))
  const tree = await getTree(flags.branch || 'main')
  const frameworkFiles = tree.filter((t) => t.type === 'blob' && t.path.startsWith('framework/'))
  if (frameworkFiles.length === 0) {
    return ok({ pulled: 0, dest, note: 'no framework files in memory-hq yet — run scripts/bootstrap-memory-hq.sh first' })
  }
  const written = []
  for (const f of frameworkFiles) {
    const file = await getFile(f.path)
    if (!file) continue
    const local = join(dest, f.path.replace(/^framework\//, ''))
    await mkdir(dirname(local), { recursive: true })
    await writeFile(local, file.content, 'utf8')
    written.push(relative(process.cwd(), local))
  }
  // Assemble a drop-in ~/.claude/CLAUDE.md from AGENT-FRAMEWORK + the
  // requested adapter (defaults to CLAUDE-CODE).
  const adapterName = flags.adapter || 'CLAUDE-CODE'
  const corePath = join(dest, 'AGENT-FRAMEWORK.md')
  const adapterPath = join(dest, 'ADAPTERS', `${adapterName}.md`)
  if (existsSync(corePath) && existsSync(adapterPath)) {
    const core = await readFile(corePath, 'utf8')
    const adapter = await readFile(adapterPath, 'utf8')
    const combined = [
      '<!-- Generated by `cli.mjs framework-pull` from memory-hq. Do not edit by hand. -->',
      '<!-- Source: framework/AGENT-FRAMEWORK.md + framework/ADAPTERS/' + adapterName + '.md -->',
      '',
      core,
      '',
      '---',
      '',
      adapter,
    ].join('\n')
    const dropin = expandHome(flags.dropIn || join('~', '.claude', 'CLAUDE.md'))
    await mkdir(dirname(dropin), { recursive: true })
    await writeFile(dropin, combined, 'utf8')
    written.push(relative(process.cwd(), dropin))
  }
  ok({ pulled: frameworkFiles.length, dest, written, adapter: adapterName })
}

async function cmdFrameworkPush(flags) {
  const src = flags.from ? expandHome(flags.from) : findFrameworkSrc()
  if (!src || !existsSync(src)) {
    throw new Error(`framework source not found (tried --from or docs/framework). Pass --from=<path>`)
  }
  const files = await collectMarkdown(src)
  let pushed = 0
  for (const localPath of files) {
    const rel = relative(src, localPath).split(sep).join('/')
    const target = `framework/${rel}`
    const content = await readFile(localPath, 'utf8')
    const existing = await getFile(target)
    await putFile(target, content, existing?.sha, `chore(framework): sync ${rel}`)
    pushed += 1
  }
  ok({ pushed, src, target: 'framework/' })
}

function expandHome(p) {
  if (!p) return p
  if (p === '~') return homedir()
  if (p.startsWith('~/')) return join(homedir(), p.slice(2))
  return p
}

function findFrameworkSrc() {
  const candidates = [
    join(process.cwd(), 'docs', 'framework'),
    join(process.cwd(), '..', 'docs', 'framework'),
  ]
  for (const c of candidates) if (existsSync(c)) return c
  return null
}

async function collectMarkdown(dir) {
  const out = []
  for (const entry of await readdir(dir)) {
    if (entry.startsWith('.')) continue
    const full = join(dir, entry)
    const s = await stat(full)
    if (s.isDirectory()) out.push(...(await collectMarkdown(full)))
    else if (entry.endsWith('.md')) out.push(full)
  }
  return out
}

